import{_ as a,o as n,c as l,ag as o}from"./chunks/framework.DXGyWiRo.js";const F=JSON.parse('{"title":"MySQL Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guides/mysql.md","filePath":"guides/mysql.md"}'),e={name:"guides/mysql.md"};function t(p,s,c,r,i,y){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="mysql-guide" tabindex="-1">MySQL Guide <a class="header-anchor" href="#mysql-guide" aria-label="Permalink to &quot;MySQL Guide&quot;">​</a></h1><p><code>MySQLClient</code> is the direct MySQL client for LinkedQL. It gives you full SQL access and transactions over a native MySQL connection, with planned realtime capabilities built on MySQL&#39;s binlog.</p><p>Use <code>MySQLClient</code> when your application talks directly to MySQL.</p><blockquote><p><code>MySQLClient</code> uses the <code>mysql2</code> connector under the hood and accepts all the existing constructor options.</p></blockquote><hr><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> MySQLClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/mysql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> MySQLClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  port</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 3306</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">root</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mydb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  poolMode</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> false</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 1 AS \`result\`</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ result: 1 }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="connection-mode" tabindex="-1">Connection Mode <a class="header-anchor" href="#connection-mode" aria-label="Permalink to &quot;Connection Mode&quot;">​</a></h2><p>By default, <code>MySQLClient</code> runs on a single PostgreSQL connection.</p><p>You can opt into connection pooling by enabling <code>poolMode</code>:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> MySQLClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  port</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 3306</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">root</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mydb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  poolMode</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>In <code>poolMode</code>, <code>MySQLClient</code> uses a connection pool to handle concurrent queries more efficiently.</p><p>After initializing the instance via <code>db.connect()</code>, subsequent <code>db.connect()</code> calls simply return a checked-out client.</p><p>This lets you explicitly check out a connection for session-sensitive work:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> client </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// ... run session-bound queries</span></span>
<span class="line"><span style="color:#BABED8;">client</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">release</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is useful for transactions or workflows that require a dedicated connection.</p><hr><h2 id="realtime-setup" tabindex="-1">Realtime Setup <a class="header-anchor" href="#realtime-setup" aria-label="Permalink to &quot;Realtime Setup&quot;">​</a></h2><p>LinkedQL is designed to integrate with MySQL&#39;s binary log (binlog) for realtime capabilities.</p><p>To make this possible, binary logging must be enabled on the MySQL server.</p><p>At minimum, set in your database config file:</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>log_bin = ON</span></span></code></pre></div><p>For correct change capture, row-based logging is recommended:</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>binlog_format = ROW</span></span></code></pre></div><p>Refer to the official MySQL documentation for enabling and configuring binary logging.</p><p>Once binary logging is available, LinkedQL can build on top of it for realtime features.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Realtime capabilities, specifically live queries and commit stream subscriptions, are not yet available on MySQL. Support for these features is planned and will build on the binlog-based foundation.</p></div><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">how this fits into larger app architectures</td><td style="text-align:left;"><a href="/guides/integration-patterns">Integration Patterns</a></td></tr><tr><td style="text-align:left;">the common API contract</td><td style="text-align:left;"><a href="/api">Core API</a></td></tr></tbody></table>`,31)])])}const d=a(e,[["render",t]]);export{F as __pageData,d as default};
